int solution(vector<vector<int>>& points){
int res=0,n=points.size();
vector<bool> inMST(n,false);
vector<int> minCostEdge(n,1e9);
vector<int> parent(n,-1);
minCostEdge[0]=0;
parent[0]=-1;
priority_queue<pair<int,int>, vector<pair<int,int>>, greater<pair<int,int>>> pq;
pq.push({0,0});
for(int i=0;i<n-1;i++){
int node=pq.top().second, cost=pq.top().first;
pq.pop();
inMST[node]=true;
for(int adjNode=0;adjNode<n;adjNode++){
if(!inMST[adjNode] && get_cost(points[node],points[adjNode])<minCostEdge[adjNode]){
minCostEdge[adjNode]=get_cost(points[node],points[adjNode]);
pq.push({minCostEdge[adjNode],adjNode});
parent[adjNode]=node;
}
}
}
for(int i=1;i<n;i++){
res+=get_cost(i,parent[i]);
}
return res;
}

int get_cost(vector<int> v1,vector<int> v2){
return abs(v1[0]-v2[0])+abs(v1[1]-v2[1])+abs(v1[2]-v2[2]);
}

