class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n))
        self.rank = [0] * n

    def find(self, i):
        if self.parent[i] != i:
            self.parent[i] = self.find(self.parent[i])
        return self.parent[i]

    def union(self, i, j):
        pi, pj = self.find(i), self.find(j)
        if pi == pj:
            return False
        if self.rank[pi] < self.rank[pj]:
            pi, pj = pj, pi
        self.parent[pj] = pi
        if self.rank[pi] == self.rank[pj]:
            self.rank[pi] += 1
        return True

def min_cost_network(attractions):
    n = len(attractions)
    edges = []
    for i in range(n):
        for j in range(i+1, n):
            cost = min(abs(attractions[i][k] - attractions[j][k]) for k in range(3))
            edges.append((i, j, cost))
    edges.sort(key=lambda e: e[2])

    uf = UnionFind(n)
    mst_cost = 0
    for e in edges:
        if uf.union(e[0], e[1]):
            mst_cost += e[2]
    return mst_cost

