   public class CityMayor {

    private G graph ;
    private Point[] points;

    public static void main(String[] args){
        CityMayor cityMayor = new CityMayor();
        cityMayor.solution(10, new int[][]{{1,5,7},{1,3,9},{2,9,4},{3,2,1},{5,9,1},{1,5,7},{1,3,9},{2,9,4},{3,2,1},{5,9,1}});
    }

    public void solution(int v, int[][] locations){
        this.points = new Point[v];
        graph = new G(v);
        for(int i=0; i<locations.length; i++){
            points[i] = new Point(locations[i][0],locations[i][1],locations[i][2]);
        }
        Arrays.sort(points,(a,b)->a.x-b.x);
        buildGraph();
        Arrays.sort(points,(a,b)->a.y-b.y);
        buildGraph();
        Arrays.sort(points,(a,b)->a.z-b.z);
        buildGraph();
        List<E> mst = graph.mst();
        for(E edge : mst){
            System.out.println("Source---->  "+edge.source.x +edge.source.y +edge.source.z +" Destination----> "+edge.destination.x +edge.destination.y +edge.destination.z +" Weight----> "+edge.weight);
        }
    }

    private void buildGraph(){
        for(int i=0; i<points.length;i++){
            if(i>0){
                Point source = points[i];
                Point destination = points[i-1];
                int dist = Math.min(Math.min(Math.abs(source.x-destination.x),Math.abs(source.y-destination.y)),Math.abs(source.z-destination.z));
                graph.addEdge(source,destination, dist);
            }
            if(i<points.length-1){
                Point source = points[i];
                Point destination = points[i+1];
                int dist = Math.min(Math.min(Math.abs(source.x-destination.x),Math.abs(source.y-destination.y)),Math.abs(source.z-destination.z));
                graph.addEdge(source,destination,dist);
            }
        }
    }

}

       class Point{
          int x;
          int y;
          int z;
          Point parent;

    public Point(int x, int y, int z){
        this.x = x;
        this.y = y;
        this.z = z;
        parent = this;
    }

    public void setParent(Point parent){
        this.parent = parent;
    }
}

       class G{
             int n;
             List<E> edges;
             public G(int n){
                this.n=n;
                this.edges = new ArrayList<>();
            }

    public void addEdge(Point source, Point destination, int weight){
        E edge = new E(source,destination,weight);
        edges.add(edge);
    }

    public List<E> mst(){
        List<E> mst = new ArrayList<>();
        Queue<E> pq = new PriorityQueue<>((a,b)->a.weight-b.weight);
        for(E edge : edges) pq.offer(edge);
        int idx = 0;
        while(idx<n && !pq.isEmpty()){
            E e = pq.remove();
            Point sourceP = find(e.source);
            Point destinationP = find(e.destination);
            if(sourceP!=destinationP){
                mst.add(e);
                idx++;
                union(sourceP,destinationP);
            }
        }
        return mst;
    }

    private void union(Point a, Point b){
        Point pA = a.parent;
        Point pB = b.parent;
        pB.parent = pA;
    }

    private Point find(Point a){
        if(a.parent==a) return a;
        return find(a.parent);
    }

}

     class E{
         Point source;
         Point destination;
          int weight;

        public E(Point source, Point destination, int weight){
            this.source = source;
            this.destination = destination;
            this.weight = weight;
    }
