using namespace std;
typedef vector<int> vec;

int main()
{
    int n;
    cin>>n;

    vector<vector<int>> C;
    for(int i=0 ; i<n ; i++){
        int x,y,z;
        cin>>x>>y>>z;
        C.push_back({x,y,z});
    }

    vector<vector<int>> adj[n];
    for(int i=0 ; i<n ; i++){
        for(int j=i+1 ; j<n ; j++){
            int cost = min({abs(C[i][0] - C[j][0]), abs(C[i][1] - C[j][1]), abs(C[i][2] - C[j][2])});
            adj[i].push_back({j, cost});
            adj[j].push_back({i, cost});
        }
    }
    priority_queue<vec, vector<vec>, greater<vec>> minH;
    vector<int> cost(n, INT_MAX);
    vector<int> MST(n, 0);

    minH.push({0, 0});
    cost[0] = 0;

    while(!minH.empty()){
        int u = minH.top()[1];
        minH.pop();

        MST[u] = 1;
        for(auto &it: adj[u]){
            int v = it[0];
            int cst = it[1];

            if(!MST[v] && cost[v] > cst){
                cost[v] = cst;
                minH.push({cost[v], v});
            }
        }
    }
    int ans = 0;
    for(int i=0 ; i<n ; i++)
        ans += cost[i];

    cout << ans << endl;
    return 0;
}
